import re
text=open('_response.md').read()
blocks=re.findall(r'```mermaid\n(.*?)```', text, re.S)
break_chars=set('():;/<>{}"')  # the chars the reviewer flagged

# Strip the shape delimiters properly, then check the INNER label text only.
# Shapes: [[X]] (subroutine), [(X)] (cylinder/db), ((X)) (circle), {X} (rhombus), [X] (rect)
def inner_labels(line):
    out=[]
    # edge text |...|
    for m in re.findall(r'\|(.*?)\|', line):
        out.append(('edge', m))
    # node shapes — order matters, match doubles first
    for m in re.findall(r'\[\[(.*?)\]\]', line): out.append(('subroutine', m))
    for m in re.findall(r'\[\((.*?)\)\]', line): out.append(('cylinder', m))
    for m in re.findall(r'\(\((.*?)\)\)', line): out.append(('circle', m))
    for m in re.findall(r'\{(.*?)\}', line): out.append(('rhombus', m))
    # plain rect [X] that's not [[ or [(
    tmp=re.sub(r'\[\[.*?\]\]','',line)
    tmp=re.sub(r'\[\(.*?\)\]','',tmp)
    for m in re.findall(r'\[([^\[\]]*?)\]', tmp): out.append(('rect', m))
    return out

problems=0
for i,b in enumerate(blocks):
    first=b.strip().splitlines()[0].strip() if b.strip() else ''
    for ln in b.splitlines():
        if 'classDef' in ln: continue
        for kind,lab in inner_labels(ln):
            core=lab
            if core.startswith('"') and core.endswith('"') and len(core)>=2:
                core=core[1:-1]
                quoted=True
            else:
                quoted=False
            bad=[c for c in core if c in break_chars]
            if bad:
                problems+=1
                print(f"BLOCK {i+1} [{kind}] quoted={quoted} BAD={bad}: label='{core}'  LINE: {ln.strip()}")
    print(f"BLOCK {i+1}: header='{first}'")
print("\nTOTAL REAL PROBLEMS (breaking chars in actual label text):", problems)
